// Generated by GitHub Copilot
import { config } from './config.js';
import { getRandomDomainRecord, upsertDomainRecord } from './repository.js';

const REALTIME_DOMAINS = ['risks', 'incidents', 'vendors', 'partners', 'controls'];
const INCIDENT_STATUS_FLOW = ['open', 'investigating', 'mitigated', 'resolved', 'closed'];
const RISK_STATUS_FLOW = ['open', 'escalated', 'mitigated', 'approved'];
const CONTROL_STATUS_FLOW = ['not-assessed', 'in-progress', 'compliant', 'non-compliant'];
const PARTNER_STATUS_FLOW = ['in-progress', 'pending-approval', 'approved', 'rejected'];
const PARTNER_STEP_FLOW = ['company-info', 'kyc-documents', 'compliance-attestation', 'review', 'approval'];
const VENDOR_STATUS_FLOW = ['active', 'under-review', 'inactive'];
const VENDOR_RATINGS = ['low', 'medium', 'high'];

/**
 * Returns the next item in a cyclical status flow.
 */
function nextInFlow(flow, currentValue) {
    const index = flow.indexOf(currentValue);
    if (index < 0) {
        return flow[0];
    }

    return flow[(index + 1) % flow.length];
}

/**
 * Mutates one record to mimic incoming real-time changes.
 */
function mutateRecord(domain, record, tickCount) {
    const nowIso = new Date().toISOString();
    const nowDate = nowIso.split('T')[0];

    if (domain === 'risks') {
        const likelihood = ((Number(record.likelihood) + 1 + tickCount) % 5) + 1;
        const impact = ((Number(record.impact) + tickCount) % 5) + 1;
        const riskScore = likelihood * impact;
        const riskLevel = riskScore >= 15 ? 'critical' : riskScore >= 10 ? 'high' : riskScore >= 5 ? 'medium' : 'low';

        return {
            ...record,
            likelihood,
            impact,
            riskScore,
            riskLevel,
            status: nextInFlow(RISK_STATUS_FLOW, String(record.status ?? 'open')),
            updatedAt: nowIso,
        };
    }

    if (domain === 'incidents') {
        return {
            ...record,
            status: nextInFlow(INCIDENT_STATUS_FLOW, String(record.status ?? 'open')),
            severity: nextInFlow(['low', 'medium', 'high', 'critical'], String(record.severity ?? 'low')),
            reportedAt: record.reportedAt ?? nowIso,
            resolvedAt: String(record.status ?? '') === 'resolved' ? nowIso : record.resolvedAt,
            updatedAt: nowIso,
        };
    }

    if (domain === 'vendors') {
        const nextRating = nextInFlow(VENDOR_RATINGS, String(record.riskRating ?? 'low'));
        const riskScore = nextRating === 'high' ? 76 : nextRating === 'medium' ? 48 : 24;

        return {
            ...record,
            riskRating: nextRating,
            riskScore,
            status: nextInFlow(VENDOR_STATUS_FLOW, String(record.status ?? 'active')),
            lastAssessmentDate: nowDate,
            updatedAt: nowIso,
        };
    }

    if (domain === 'partners') {
        return {
            ...record,
            status: nextInFlow(PARTNER_STATUS_FLOW, String(record.status ?? 'in-progress')),
            currentStep: nextInFlow(PARTNER_STEP_FLOW, String(record.currentStep ?? 'company-info')),
            submittedAt: record.submittedAt ?? nowDate,
            approvedAt: String(record.status ?? '') === 'approved' ? nowDate : record.approvedAt,
            updatedAt: nowIso,
        };
    }

    if (domain === 'controls') {
        return {
            ...record,
            status: nextInFlow(CONTROL_STATUS_FLOW, String(record.status ?? 'not-assessed')),
            lastAssessedDate: nowDate,
            evidenceCount: Math.max(1, Number(record.evidenceCount ?? 0) + 1),
            updatedAt: nowIso,
        };
    }

    return {
        ...record,
        updatedAt: nowIso,
    };
}

/**
 * Starts a deterministic background simulator for real-time backend events.
 */
export function startRealtimeSimulator({ onEvent }) {
    if (!config.realtimeEnabled) {
        return () => undefined;
    }

    let tick = 0;

    const timerId = setInterval(async () => {
        tick += 1;

        const domain = REALTIME_DOMAINS[tick % REALTIME_DOMAINS.length];

        try {
            const current = await getRandomDomainRecord(domain);
            if (!current) {
                return;
            }

            const updated = mutateRecord(domain, current, tick);
            await upsertDomainRecord(domain, String(updated.id), updated);

            onEvent({
                eventType: 'domain.updated',
                payload: {
                    domain,
                    id: updated.id,
                    source: 'realtime-simulator',
                },
            });
        } catch (error) {
            onEvent({
                eventType: 'simulator.error',
                payload: {
                    message: error instanceof Error ? error.message : 'Unknown realtime simulator error',
                },
            });
        }
    }, config.realtimeTickMs);

    return () => {
        clearInterval(timerId);
    };
}
